import argparse
import json
import socket
import struct
import threading
import time
from dataclasses import dataclass, field
from typing import Dict, List, Tuple, Optional


@dataclass
class Player:
    name: str
    score: int = 0
    ping: int = 0
    team: str = "spectator"


@dataclass
class GameState:
    server_name: str = "My Game Server"
    map_name: str = "default_map"
    game_mode: str = "deathmatch"
    max_players: int = 32
    current_players: int = 0
    version: str = "1.0.0"
    description: str = "A UDP game server status endpoint"
    uptime_seconds: int = 0
    extra: Dict[str, str] = field(default_factory=dict)


class GameServer:
    def __init__(self, host: str, port: int):
        self.host = host
        self.port = port
        self.players: List[Player] = []
        self.state = GameState()
        self.lock = threading.Lock()
        self.running = False
        self.start_time = time.time()
        self.sock: Optional[socket.socket] = None
        self._populate_demo_data()

    def _populate_demo_data(self):
        with self.lock:
            self.players = [
                Player(name=f"Player{i:03d}", score=i * 10, ping=20 + (i % 80), team="red" if i % 2 == 0 else "blue")
                for i in range(1, 101)
            ]
            self.state.current_players = len(self.players)
            self.state.extra = {
                "region": "global",
                "anti_cheat": "enabled",
                "friendly_fire": "off",
                "tick_rate": "60",
            }

    def _build_status_payload(self) -> bytes:
        with self.lock:
            self.state.uptime_seconds = int(time.time() - self.start_time)
            self.state.current_players = len(self.players)
            payload = {
                "status": "ok",
                "server": {
                    "name": self.state.server_name,
                    "map": self.state.map_name,
                    "mode": self.state.game_mode,
                    "version": self.state.version,
                    "description": self.state.description,
                    "uptime_seconds": self.state.uptime_seconds,
                    "max_players": self.state.max_players,
                    "current_players": self.state.current_players,
                    "extra": self.state.extra,
                },
                "players": [
                    {
                        "name": p.name,
                        "score": p.score,
                        "ping": p.ping,
                        "team": p.team,
                    }
                    for p in self.players
                ],
            }
        return json.dumps(payload, separators=(",", ":"), ensure_ascii=False).encode("utf-8")

    def _build_chunked_response(self, payload: bytes, chunk_size: int = 1200) -> List[bytes]:
        total_chunks = (len(payload) + chunk_size - 1) // chunk_size
        if total_chunks <= 1:
            return [payload]
        chunks = []
        for idx in range(total_chunks):
            start = idx * chunk_size
            end = min(start + chunk_size, len(payload))
            header = struct.pack("!4sHH", b"STAT", total_chunks, idx)
            chunks.append(header + payload[start:end])
        return chunks

    def _handle_packet(self, data: bytes, addr: Tuple[str, int]):
        try:
            text = data.decode("utf-8", errors="ignore").strip()
        except Exception:
            text = ""

        if text.upper() in {"STATUS", "INFO", "QUERY", "GET_STATUS"} or data == b"\x01":
            payload = self._build_status_payload()
            for chunk in self._build_chunked_response(payload):
                try:
                    self.sock.sendto(chunk, addr)
                except Exception:
                    pass
            return

        if text.upper().startswith("SET "):
            try:
                _, key, value = text.split(" ", 2)
                with self.lock:
                    if hasattr(self.state, key):
                        setattr(self.state, key, value)
                        self.sock.sendto(b"OK", addr)
                    else:
                        self.state.extra[key] = value
                        self.sock.sendto(b"OK", addr)
            except Exception:
                self.sock.sendto(b"ERR", addr)
            return

        if text.upper() == "PING":
            self.sock.sendto(b"PONG", addr)
            return

        if text.upper() == "HELP":
            self.sock.sendto(b"COMMANDS: STATUS, INFO, QUERY, GET_STATUS, PING, HELP", addr)
            return

        self.sock.sendto(b"UNKNOWN", addr)

    def serve_forever(self):
        self.running = True
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.bind((self.host, self.port))
        self.sock.settimeout(1.0)

        while self.running:
            try:
                data, addr = self.sock.recvfrom(65535)
            except socket.timeout:
                continue
            except OSError:
                break
            threading.Thread(target=self._handle_packet, args=(data, addr), daemon=True).start()

        try:
            self.sock.close()
        except Exception:
            pass

    def stop(self):
        self.running = False
        if self.sock:
            try:
                self.sock.close()
            except Exception:
                pass


def main():
    parser = argparse.ArgumentParser(description="UDP game server status endpoint")
    parser.add_argument("--host", default="0.0.0.0")
    parser.add_argument("--port", type=int, default=27015)
    args = parser.parse_args()

    server = GameServer(args.host, args.port)
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        server.stop()


if __name__ == "__main__":
    main()